const aws = require('aws-sdk');
const sharp = require('sharp');
const { spawn }  =require("child_process"); //import child process from child_process npm module.


exports.handler = (event, context) => {
    const params = event['Records'][0]['s3']['object']; //get the params and return the event.
    const bucketName = params["bucket"]["name"];
    const key = params["key"];
    var file = key;
    var format = "";
    for (var i in params){
        if(params[i]["value"] == ".jpg"){
            format = "JPEG";
        }else if(params[i]["value"]== ".png" ){
            format ="PNG";
        }

    }
    var newImageName  = key.replace(".jpg", "."+format); //if key was image.jpg, newImageName would be image.jpeg
    sharp(file).toFormat(format) .toFile("./image/"+newImageName , (err)=>{}); //toFile takes 2 arguments: first is destination directory of new image and second is callBack function that will be executed when the conversion is complete
    return console.log(`Converted image from ${key} to ${newImageName}`);
};


